1	/**
2	 * Integration tests for the Scheduler (src/server/scheduler/scheduler.ts).
3	 *
4	 * Uses real SQLite (with migrations) and stub ProcessManager / WorktreeManager
5	 * so no real git, worktrees, or agent processes are required.
6	 *
7	 * Coverage:
8	 *   AC-1  ingestWorkflow seeds workflow + item rows within the poll window.
9	 *   AC-2  Crash recovery transitions stale in_progress → awaiting_retry before
10	 *         any new items are scheduled.
11	 *   AC-3  Scheduler drives pending → ready → bootstrapping → in_progress →
12	 *         complete (or a terminal state) end-to-end for a single-phase workflow.
13	 *   AC-5  applyWorktreeCreated persists branch_name + worktree_path to workflows.
14	 *   AC-7  BroadcastFn is called with stream events forwarded from the parser.
15	 *   AC-8  stop() resolves after cancelling in-flight sessions (graceful drain).
16	 *   RC-5  Concurrency limit (maxParallel=1) prevents over-scheduling.
17	 *   RC-6  All production deps are injectable (verified by using stubs throughout).
18	 */
19	
20	import { describe, it, expect, beforeEach, afterEach } from 'vitest';
21	import { EventEmitter } from 'node:events';
22	import fs from 'node:fs';
23	import os from 'node:os';
24	import path from 'node:path';
25	import { fileURLToPath } from 'node:url';
26	import { openDbPool } from '../../src/server/storage/db.js';
27	import { applyMigrations } from '../../src/server/storage/migrate.js';
28	import type { DbPool } from '../../src/server/storage/db.js';
29	import type { ProcessManager, SpawnHandle, SpawnOpts } from '../../src/server/process/manager.js';
30	import type { WorktreeManager, WorktreeInfo, BootstrapEvent } from '../../src/server/worktree/manager.js';
31	import { Scheduler } from '../../src/server/scheduler/scheduler.js';
32	import { ingestWorkflow } from '../../src/server/scheduler/ingest.js';
33	import type { ResolvedConfig } from '../../src/shared/types/config.js';
34	
35	// ---------------------------------------------------------------------------
36	// Test infrastructure
37	// ---------------------------------------------------------------------------
38	
39	const __dirname = path.dirname(fileURLToPath(import.meta.url));
40	const MIGRATIONS_DIR = path.resolve(__dirname, '../..', 'src/server/storage/migrations');
41	
42	let tmpDir: string;
43	let db: DbPool;
44	// Track schedulers so they're stopped before db.close() in afterEach.
45	const activeSchedulers: Scheduler[] = [];
46	
47	beforeEach(() => {
48	  tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'yoke-sched-test-'));
49	  db = openDbPool(path.join(tmpDir, 'test.db'));
50	  applyMigrations(db.writer, MIGRATIONS_DIR);
51	});
52	
53	afterEach(async () => {
54	  // Stop all schedulers before closing the DB — timers must not fire after close.
55	  for (const s of activeSchedulers) {
56	    await s.stop().catch(() => {});
57	  }
58	  activeSchedulers.length = 0;
59	  db.close();
60	  fs.rmSync(tmpDir, { recursive: true, force: true });
61	});
62	
63	// ---------------------------------------------------------------------------
64	// Minimal ResolvedConfig factory
65	// ---------------------------------------------------------------------------
66	
67	function makeConfig(overrides: Partial<ResolvedConfig> = {}): ResolvedConfig {
68	  return {
69	    version: '1',
70	    configDir: tmpDir,
71	    project: { name: 'test-project' },
72	    pipeline: {
73	      stages: [
74	        {
75	          id: 'stage-alpha',
76	          run: 'once',
77	          phases: ['phase-one'],
78	        },
79	      ],
80	    },
81	    phases: {
82	      'phase-one': {
83	        command: 'claude',
84	        args: ['--output-format', 'stream-json'],
85	        prompt_template: 'Do the thing.',
86	      },
87	    },
88	    ...overrides,
89	  };
90	}
91	
92	// ---------------------------------------------------------------------------
93	// Stub SpawnHandle — an EventEmitter that replays records on next tick.
94	// ---------------------------------------------------------------------------
95	
96	type StubRecord =
97	  | { type: 'stdout'; line: string }
98	  | { type: 'stderr'; chunk: string }
99	  | { type: 'exit'; code: number };
100	
101	class StubSpawnHandle extends EventEmitter implements SpawnHandle {
102	  readonly pid = 99001;
103	  readonly pgid = 99001;
104	  private _alive = true;
105	
106	  constructor(private readonly records: StubRecord[] = []) {
107	    super();
108	  }
109	
110	  isAlive(): boolean { return this._alive; }
111	
112	  async cancel(): Promise<void> {
113	    this._alive = false;
114	    setImmediate(() => this.emit('exit', null, 'SIGTERM'));
115	  }
116	
117	  start(): void {
118	    const records = this.records;
119	    let i = 0;
120	    const emit = () => {
121	      if (!this._alive || i >= records.length) {
122	        if (this._alive) { this._alive = false; this.emit('exit', 0, null); }
123	        return;
124	      }
125	      const rec = records[i++];
126	      if (rec.type === 'stdout') this.emit('stdout_line', rec.line);
127	      else if (rec.type === 'stderr') this.emit('stderr_data', rec.chunk);
128	      else if (rec.type === 'exit') {
129	        this._alive = false;
130	        this.emit('exit', rec.code, null);
131	        return;
132	      }
133	      setImmediate(emit);
134	    };
135	    setImmediate(emit);
136	  }
137	}
138	
139	// ---------------------------------------------------------------------------
140	// Stub ProcessManager
141	// ---------------------------------------------------------------------------
142	
143	class StubProcessManager implements ProcessManager {
144	  readonly handles: StubSpawnHandle[] = [];
145	
146	  constructor(private readonly records: StubRecord[] = []) {}
147	
148	  async spawn(_opts: SpawnOpts): Promise<SpawnHandle> {
149	    const handle = new StubSpawnHandle(this.records);
150	    this.handles.push(handle);
151	    handle.start();
152	    return handle;
153	  }
154	}
155	
156	// ---------------------------------------------------------------------------
157	// Stub WorktreeManager (only implements the methods the scheduler calls)
158	// ---------------------------------------------------------------------------
159	
160	function makeWorktreeManager(opts: {
161	  worktreePath?: string;
162	  bootstrapEvent?: BootstrapEvent;
163	  failCreate?: boolean;
164	} = {}): WorktreeManager {
165	  const wt = opts.worktreePath ?? path.join(tmpDir, 'wt');
166	  fs.mkdirSync(wt, { recursive: true });
167	  return {
168	    async createWorktree(): Promise<WorktreeInfo> {
169	      if (opts.failCreate) throw new Error('createWorktree stub failure');
170	      return { branchName: 'yoke/test-abc123', worktreePath: wt };
171	    },
172	    async runBootstrap(): Promise<BootstrapEvent> {
173	      return opts.bootstrapEvent ?? { type: 'bootstrap_ok' };
174	    },
175	    // cleanup is never called by the scheduler directly
176	    async cleanup(): Promise<{ worktreeRemoved: boolean; branchRetained: boolean }> {
177	      return { worktreeRemoved: true, branchRetained: false };
178	    },
179	  } as unknown as WorktreeManager;
180	}
181	
182	// ---------------------------------------------------------------------------
183	// pollUntil — wait for a SQLite condition to become true
184	// ---------------------------------------------------------------------------
185	
186	async function pollUntil(
187	  check: () => boolean,
188	  { timeoutMs = 5000, intervalMs = 50 } = {},
189	): Promise<void> {
190	  const deadline = Date.now() + timeoutMs;
191	  while (Date.now() < deadline) {
192	    if (check()) return;
193	    await new Promise((r) => setTimeout(r, intervalMs));
194	  }
195	  throw new Error('pollUntil timed out');
196	}
197	
198	// ---------------------------------------------------------------------------
199	// Helper — create and start a minimal Scheduler, return it + broadcastFn spy
200	// ---------------------------------------------------------------------------
201	
202	interface TestSchedulerResult {
203	  scheduler: Scheduler;
204	  broadcasts: Array<{ workflowId: string; sessionId: string | null; frameType: string; payload: unknown }>;
205	}
206	
207	function buildScheduler(opts: {
208	  config?: ResolvedConfig;
209	  processManager?: ProcessManager;
210	  worktreeManager?: WorktreeManager;
211	  maxParallel?: number;
212	  pollIntervalMs?: number;
213	}): TestSchedulerResult {
214	  const broadcasts: TestSchedulerResult['broadcasts'] = [];
215	
216	  const scheduler = new Scheduler({
217	    db,
218	    config: opts.config ?? makeConfig(),
219	    processManager: opts.processManager ?? new StubProcessManager(),
220	    worktreeManager: opts.worktreeManager ?? makeWorktreeManager(),
221	    prepostRunner: async () => ({ kind: 'complete' }),
222	    assemblePrompt: async () => 'stub prompt',
223	    broadcast: (workflowId, sessionId, frameType, payload) => {
224	      broadcasts.push({ workflowId, sessionId, frameType, payload });
225	    },
226	    maxParallel: opts.maxParallel ?? 4,
227	    pollIntervalMs: opts.pollIntervalMs ?? 50,
228	    gracePeriodMs: 500,
229	  });
230	
231	  activeSchedulers.push(scheduler);
232	  return { scheduler, broadcasts };
233	}
234	
235	// ---------------------------------------------------------------------------
236	// AC-1: ingestWorkflow
237	// ---------------------------------------------------------------------------
238	
239	describe('AC-1: ingestWorkflow', () => {
240	  it('creates a workflow row and one item per stage', () => {
241	    const config = makeConfig();
242	    const { workflowId, isResume } = ingestWorkflow(db, config);
243	
244	    expect(typeof workflowId).toBe('string');
245	    expect(isResume).toBe(false);
246	
247	    const wf = db.reader()
248	      .prepare('SELECT * FROM workflows WHERE id = ?')
249	      .get(workflowId) as { status: string; current_stage: string } | undefined;
250	    expect(wf).toBeDefined();
251	    expect(wf!.status).toBe('pending');
252	    expect(wf!.current_stage).toBe('stage-alpha');
253	
254	    const items = db.reader()
255	      .prepare('SELECT * FROM items WHERE workflow_id = ?')
256	      .all(workflowId) as { stage_id: string; status: string }[];
257	    expect(items).toHaveLength(1);
258	    expect(items[0].stage_id).toBe('stage-alpha');
259	    expect(items[0].status).toBe('pending');
260	  });
261	
262	  it('returns isResume:true and the existing id on second call', () => {
263	    const config = makeConfig();
264	    const first = ingestWorkflow(db, config);
265	    const second = ingestWorkflow(db, config);
266	
267	    expect(second.workflowId).toBe(first.workflowId);
268	    expect(second.isResume).toBe(true);
269	  });
270	
271	  it('chains depends_on across stages (stage N+1 depends on stage N item)', () => {
272	    const config = makeConfig({
273	      pipeline: {
274	        stages: [
275	          { id: 's1', run: 'once', phases: ['phase-one'] },
276	          { id: 's2', run: 'once', phases: ['phase-one'] },
277	        ],
278	      },
279	    });
280	    const { workflowId } = ingestWorkflow(db, config);
281	    const items = db.reader()
282	      .prepare('SELECT id, stage_id, depends_on FROM items WHERE workflow_id = ? ORDER BY rowid')
283	      .all(workflowId) as { id: string; stage_id: string; depends_on: string | null }[];
284	
285	    expect(items).toHaveLength(2);
286	    expect(items[0].depends_on).toBeNull();  // first item has no dependency
287	    const deps = JSON.parse(items[1].depends_on!);
288	    expect(deps).toEqual([items[0].id]);     // second depends on first
289	  });
290	});
291	
292	// ---------------------------------------------------------------------------
293	// AC-2: Crash recovery runs before scheduling
294	// ---------------------------------------------------------------------------
295	
296	describe('AC-2: crash recovery before scheduling', () => {
297	  it('transitions stale in_progress items to awaiting_retry before any spawn', async () => {
298	    // Manually seed a workflow + item in in_progress + a sessions row simulating
299	    // a stale session from a previous run.
300	    const config = makeConfig();
301	    const { workflowId } = ingestWorkflow(db, config);
302	
303	    // Advance item to in_progress by hand.
304	    const [item] = db.reader()
305	      .prepare('SELECT id FROM items WHERE workflow_id = ?')
306	      .all(workflowId) as { id: string }[];
307	
308	    const now = new Date().toISOString();
309	    db.writer.prepare('UPDATE items SET status = ? WHERE id = ?').run('in_progress', item.id);
310	    // Insert a stale sessions row with a non-existent PID so buildCrashRecovery
311	    // detects it as stale (probeProcess returns false for PID 2147483647).
312	    const sessionId = 'stale-session-id';
313	    db.writer.prepare(`
314	      INSERT INTO sessions (id, workflow_id, item_id, stage, phase, agent_profile,
315	                            status, pid, pgid, started_at)
316	      VALUES (?, ?, ?, 'stage-alpha', 'phase-one', 'default', 'running', 2147483647, 2147483647, ?)
317	    `).run(sessionId, workflowId, item.id, now);
318	
319	    const { scheduler } = buildScheduler({ config });
320	    await scheduler.start();
321	
322	    // After start(), the stale in_progress item should have been moved out
323	    // of in_progress (awaiting_retry or awaiting_user) before any new spawn.
324	    const freshItem = db.reader()
325	      .prepare('SELECT status FROM items WHERE id = ?')
326	      .get(item.id) as { status: string };
327	
328	    expect(['awaiting_retry', 'awaiting_user']).toContain(freshItem.status);
329	
330	    await scheduler.stop();
331	  });
332	});
333	
334	// ---------------------------------------------------------------------------
335	// AC-3: End-to-end state machine advancement
336	// ---------------------------------------------------------------------------
337	
338	describe('AC-3: state machine end-to-end', () => {
339	  it('drives a single-stage workflow from pending to complete', async () => {
340	    const config = makeConfig();
341	    const pm = new StubProcessManager([{ type: 'exit', code: 0 }]);
342	    const { scheduler } = buildScheduler({ config, processManager: pm, pollIntervalMs: 50 });
343	
344	    await scheduler.start();
345	    const workflowId = scheduler.workflowId!;
346	
347	    // Wait for the workflow to reach 'completed' status.
348	    await pollUntil(() => {
349	      const wf = db.reader()
350	        .prepare('SELECT status FROM workflows WHERE id = ?')
351	        .get(workflowId) as { status: string } | undefined;
352	      return wf?.status === 'completed';
353	    }, { timeoutMs: 10_000 });
354	
355	    const wf = db.reader()
356	      .prepare('SELECT status FROM workflows WHERE id = ?')
357	      .get(workflowId) as { status: string };
358	    expect(wf.status).toBe('completed');
359	
360	    await scheduler.stop();
361	  });
362	
363	  it('bootstrap_fail → item enters bootstrap_failed or awaiting_user', async () => {
364	    const config = makeConfig();
365	    const wm = makeWorktreeManager({ bootstrapEvent: { type: 'bootstrap_fail', failedCommand: 'setup.sh', exitCode: 1, stderr: 'oops' } });
366	    const { scheduler } = buildScheduler({ config, worktreeManager: wm });
367	
368	    await scheduler.start();
369	    const workflowId = scheduler.workflowId!;
370	
371	    const [item] = db.reader()
372	      .prepare('SELECT id FROM items WHERE workflow_id = ?')
373	      .all(workflowId) as { id: string }[];
374	
375	    await pollUntil(() => {
376	      const row = db.reader()
377	        .prepare('SELECT status FROM items WHERE id = ?')
378	        .get(item.id) as { status: string };
379	      return ['bootstrap_failed', 'awaiting_user'].includes(row.status);
380	    }, { timeoutMs: 10_000 });
381	
382	    const row = db.reader()
383	      .prepare('SELECT status FROM items WHERE id = ?')
384	      .get(item.id) as { status: string };
385	    expect(['bootstrap_failed', 'awaiting_user']).toContain(row.status);
386	
387	    await scheduler.stop();
388	  });
389	});
390	
391	// ---------------------------------------------------------------------------
392	// AC-5: applyWorktreeCreated persists worktree path
393	// ---------------------------------------------------------------------------
394	
395	describe('AC-5: worktree_path persisted after createWorktree', () => {
396	  it('sets branch_name and worktree_path on the workflow row', async () => {
397	    const config = makeConfig();
398	    const pm = new StubProcessManager([{ type: 'exit', code: 0 }]);
399	    const wm = makeWorktreeManager({ worktreePath: path.join(tmpDir, 'my-wt') });
400	    const { scheduler } = buildScheduler({ config, processManager: pm, worktreeManager: wm });
401	
402	    await scheduler.start();
403	    const workflowId = scheduler.workflowId!;
404	
405	    // Wait for worktree_path to be set (happens before session spawn).
406	    await pollUntil(() => {
407	      const wf = db.reader()
408	        .prepare('SELECT worktree_path FROM workflows WHERE id = ?')
409	        .get(workflowId) as { worktree_path: string | null };
410	      return wf.worktree_path != null;
411	    });
412	
413	    const wf = db.reader()
414	      .prepare('SELECT branch_name, worktree_path FROM workflows WHERE id = ?')
415	      .get(workflowId) as { branch_name: string; worktree_path: string };
416	
417	    expect(wf.branch_name).toBe('yoke/test-abc123');
418	    expect(wf.worktree_path).toContain('my-wt');
419	
420	    await scheduler.stop();
421	  });
422	});
423	
424	// ---------------------------------------------------------------------------
425	// AC-7: BroadcastFn receives stream events
426	// ---------------------------------------------------------------------------
427	
428	describe('AC-7: stream events are broadcast', () => {
429	  it('calls broadcast with item.state frames', async () => {
430	    const config = makeConfig();
431	    const pm = new StubProcessManager([{ type: 'exit', code: 0 }]);
432	    const { scheduler, broadcasts } = buildScheduler({ config, processManager: pm });
433	
434	    await scheduler.start();
435	    const workflowId = scheduler.workflowId!;
436	
437	    await pollUntil(() => {
438	      const wf = db.reader()
439	        .prepare('SELECT status FROM workflows WHERE id = ?')
440	        .get(workflowId) as { status: string } | undefined;
441	      return wf?.status === 'completed';
442	    }, { timeoutMs: 10_000 });
443	
444	    // item.state frames should have been broadcast.
445	    const stateFrames = broadcasts.filter((b) => b.frameType === 'item.state');
446	    expect(stateFrames.length).toBeGreaterThan(0);
447	
448	    // All item.state frames should reference the correct workflowId.
449	    for (const frame of stateFrames) {
450	      expect(frame.workflowId).toBe(workflowId);
451	    }
452	
453	    await scheduler.stop();
454	  });
455	});
456	
457	// ---------------------------------------------------------------------------
458	// AC-8: stop() drains in-flight sessions
459	// ---------------------------------------------------------------------------
460	
461	describe('AC-8: graceful drain on stop()', () => {
462	  it('resolves within gracePeriodMs even with a running session', async () => {
463	    const config = makeConfig();
464	
465	    // A process that never exits on its own — stalls until cancel() fires SIGTERM.
466	    class StallingPM implements ProcessManager {
467	      readonly handles: StubSpawnHandle[] = [];
468	      async spawn(_opts: SpawnOpts): Promise<SpawnHandle> {
469	        const handle = new StubSpawnHandle([]);
470	        // Override start() — do nothing. Only cancel() can unblock it.
471	        handle.start = () => { /* stall — never emit exit spontaneously */ };
472	        this.handles.push(handle);
473	        return handle;
474	      }
475	    }
476	    const pm = new StallingPM();
477	    const broadcasts: TestSchedulerResult['broadcasts'] = [];
478	    const sched = new Scheduler({
479	      db,
480	      config,
481	      processManager: pm,
482	      worktreeManager: makeWorktreeManager(),
483	      prepostRunner: async () => ({ kind: 'complete' }),
484	      assemblePrompt: async () => 'stub prompt',
485	      broadcast: (wid, sid, ft, p) => broadcasts.push({ workflowId: wid, sessionId: sid, frameType: ft, payload: p }),
486	      maxParallel: 4,
487	      pollIntervalMs: 50,
488	      gracePeriodMs: 1000,
489	    });
490	    activeSchedulers.push(sched);
491	
492	    await sched.start();
493	
494	    // Wait for at least one spawn (handle appears in pm.handles).
495	    await pollUntil(() => (pm as StallingPM).handles.length > 0, { timeoutMs: 10_000 });
496	
497	    const t0 = Date.now();
498	    await sched.stop();
499	    const elapsed = Date.now() - t0;
500	
501	    // Should complete within gracePeriodMs + generous buffer.
502	    expect(elapsed).toBeLessThan(3000);
503	  });
504	});
505	
506	// ---------------------------------------------------------------------------
